+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends [AspectTrait, AspectTrait, ...AspectTrait[]]>(
+    ...inputs: T
+): Aspect<T> {
+    const traits: Trait[] = [];
+    const names = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const input of inputs) {
+        const constituents = isAspect(input) ? input.traits : [input];
+        for (const constituent of constituents) {
+            if (constituent[$internal].relation) {
+                throw new Error('Relations cannot be constituents of an aspect');
+            }
+            if (traits.includes(constituent)) continue;
+            for (const name of Object.keys(constituent.schema)) {
+                if (names.has(name)) {
+                    throw new Error(`Aspect constituents cannot share the field "${name}"`);
+                }
+                names.add(name);
+                schema[name] = (constituent.schema as Record<string, unknown>)[name];
+            }
+            traits.push(constituent);
+        }
+    }
+
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits),
+        schema: Object.freeze(schema),
+    }) as Aspect<T>;
+}
+
+export function getAspectValue(
+    get: (trait: Trait) => TraitRecord<Trait> | undefined,
+    aspect: Aspect
+): AspectRecord<Aspect> | undefined {
+    const value: Record<string, unknown> = {};
+    for (const trait of aspect.traits) {
+        const data = get(trait);
+        if (data === undefined) return undefined;
+        Object.assign(value, data);
+    }
+    return value as AspectRecord<Aspect>;
+}
+
+export function splitAspectValue(aspect: Aspect, value: Record<string, unknown>) {
+    return aspect.traits.map((trait) => {
+        const fields: Record<string, unknown> = {};
+        for (const name of Object.keys(trait.schema as Schema)) {
+            if (name in value) fields[name] = value[name];
+        }
+        return [trait, fields] as const;
+    });
+}
